      "x-eq-source-aliases": ["frequency", "service_interval", "pm_frequency", "maintenance_frequency", "service_cadence", "inspection_frequency", "pm_interval", "service_frequency", "maint_freq", "service_period", "ppm_frequency", "ppm interval"],
