      "x-eq-coerce": "date"
    },
    "next_service_due": {
      "type": ["string", "null"],
      "format": "date",
      "x-eq-source-aliases": ["next_pm", "due_date", "next_due", "next_inspection", "next_service", "scheduled_service", "due", "next_maintenance", "service_due", "pm_due", "next_check", "next_test", "next_pm_date", "due_for_service", "next_service_date"],
      "x-eq-coerce": "date"
    },
    "location_in_site": {
      "type": ["string", "null"],
