    },
    "barcode": {
      "type": ["string", "null"],
      "description": "Barcode or QR code value for scan-based identification.",
      "x-eq-source-aliases": ["qr", "qr_code", "barcode_value", "scan_code", "barcode_id", "bar_code", "qr_value", "scannable_id", "rfid"]
    },
    "active": {
      "type": "boolean",
      "x-eq-source-aliases": ["is_active", "current", "status", "in_service", "enabled", "state", "asset_status", "operational", "in_use", "live"],
      "x-eq-coerce": "boolean",
      "default": true
    },
    "defects_summary": {
      "type": ["string", "null"],
      "description": "Short denormalised summary of open issues against this asset. Convenience field for one-glance views — the structured per-defect records live in the asset_defect entity. Example: ''RCD board 2 to be replaced; door hinge bent''.",
      "x-eq-source-aliases": ["defects", "open_defects", "defect_summary", "outstanding_defects", "issues", "asset_issues", "problems", "faults", "defects_outstanding", "open_issues", "fault_summary"],
      "maxLength": 500
    },
    "client_classification": {
      "type": ["object", "null"],
      "description": "Customer-imposed asset taxonomy preserved verbatim. Used when a client requires their own classification scheme on their assets (e.g. data centre operator''s Maximo IAM values, principal contractor''s compliance taxonomy). Stays as free-form so client-specific structure isn''t coerced into our canonical enums. Set programmatically by importers when a source spreadsheet carries 50+ extra columns of customer-side metadata.",
      "additionalProperties": true,
      "x-eq-source-aliases": ["client_class", "customer_taxonomy", "client_attributes", "client_metadata", "external_classification", "client_taxonomy"]
    },
    "notes": {
      "type": ["string", "null"],
      "x-eq-source-aliases": ["comment", "comments", "remarks", "note", "note_text", "observations", "additional_notes", "free_text", "general_notes", "additional_info"],
      "maxLength": 4000
    },
    "imported_at": { "type": ["string", "null"], "format": "date-time", "x-eq-system-managed": true },
    "imported_from": { "type": ["string", "null"], "x-eq-system-managed": true }
  },
  "x-eq-cross-field-rules": [
    {
      "id": "next_after_last",
      "rule": "next_service_due == null OR last_service_date == null OR next_service_due > last_service_date",
      "message": "Next service due is not after last service date."
    },
    {
      "id": "warranty_after_install",
      "rule": "warranty_expires == null OR install_date == null OR warranty_expires > install_date",
      "message": "Warranty expiry is before install date."
    }
  ],
  "x-eq-import-hints": {
    "description": "Asset registers come in wildly different shapes. The header row is rarely on row 1.",
    "common_sources": [
      {
        "name": "Existing PM contractor''s register",
        "typical_columns": ["Tag", "Description", "Manufacturer", "Model", "Serial", "Last PM", "Next PM", "Frequency"],
        "watchouts": ["Often has merged header rows", "Frequency may be coded (''M'', ''Q'', ''6M'', ''A'') — may need separate schedule field"]
      },
      {
        "name": "Client''s facilities export (head office originated)",
        "typical_columns": ["Asset No", "Building", "Floor", "Room", "Asset Description", "Make/Model", "Install Date"],
        "watchouts": ["Building/Floor/Room often need concatenating into location_in_site", "Make/Model may be combined — needs splitting"]
      },
      {
        "name": "Hand-built electrical asset list",
        "typical_columns": ["Switchboard", "Circuit", "Description", "Amps"],
        "watchouts": ["Each row is often a sub-asset of a switchboard — parent_asset_id must be inferred from grouping"]
      }
    ]
  }
}
