insert into eq_schema_registry (entity, module, version, schema_json, description, is_current)
values ('staff', 'field', '1.0.0', '{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://schemas.eq.solutions/field/staff/v1.json",
  "title": "Staff",
  "description": "A staff member who can be scheduled to sites. Includes employees, subcontractors, and labour-hire workers.",
  "type": "object",
  "x-eq-entity": "staff",
  "x-eq-module": "field",
  "x-eq-version": "1.0.0",
  "x-eq-table": "staff",
  "required": ["staff_id", "tenant_id", "first_name", "last_name", "employment_type", "active"],
  "properties": {
    "staff_id": {
      "type": "string",
      "format": "uuid",
      "description": "Internal canonical ID. Generated on import if not provided.",
      "x-eq-source-aliases": ["id", "staff_id", "employee_id", "emp_id", "worker_id", "person_id"],
      "x-eq-required-on-import": false
    },
    "tenant_id": {
      "type": "string",
      "format": "uuid",
      "description": "Owning tenant. Set automatically by import context.",
      "x-eq-system-managed": true
    },
    "external_id": {
      "type": ["string", "null"],
      "description": "Customer''s own ID for this staff member (payroll number, HR system ID, etc). Preserved for round-trip exports.",
      "x-eq-source-aliases": ["payroll_no", "payroll_number", "hr_id", "employee_number", "staff_no", "ref", "code"],
      "maxLength": 64
    },
    "first_name": {
      "type": "string",
      "description": "Given name. Required.",
      "x-eq-source-aliases": ["first", "given_name", "fname", "firstname", "forename"],
      "minLength": 1,
      "maxLength": 80
    },
    "last_name": {
      "type": "string",
      "description": "Family name. Required.",
      "x-eq-source-aliases": ["last", "surname", "lname", "lastname", "family_name"],
      "minLength": 1,
      "maxLength": 80
    },
    "preferred_name": {
      "type": ["string", "null"],
      "description": "What the person actually goes by on site. Often a nickname.",
      "x-eq-source-aliases": ["nickname", "called", "goes_by", "display_name"],
      "maxLength": 80
    },
    "email": {
      "type": ["string", "null"],
      "format": "email",
      "description": "Primary email. Used for invitations and notifications.",
      "x-eq-source-aliases": ["email_address", "e_mail", "mail", "work_email"]
    },
    "phone": {
      "type": ["string", "null"],
      "description": "Primary mobile. Stored as E.164 where possible (e.g. +61412345678).",
      "x-eq-source-aliases": ["mobile", "phone_number", "cell", "contact_number", "ph"],
      "x-eq-coerce": "phone-au"
    },
    "employment_type": {
      "type": "string",
      "enum": ["employee", "subcontractor", "labour_hire", "casual", "apprentice"],
      "description": "Engagement type. Drives leave entitlements, charge-out treatment, compliance requirements.",
      "x-eq-source-aliases": ["type", "engagement", "employment", "employee_type", "category"],
      "x-eq-enum-aliases": {
        "employee": ["full-time", "ft", "permanent", "perm", "fulltime", "salaried"],
        "subcontractor": ["sub", "subbie", "contractor", "subcontract", "sub-contractor"],
        "labour_hire": ["labour-hire", "agency", "labourer", "labour hire", "hired"],
        "casual": ["pt", "part-time", "parttime", "casual_emp"],
        "apprentice": ["apprentice", "appy", "trainee"]
      }
    },
    "trade": {
      "type": ["string", "null"],
      "description": "Primary trade discipline. Free text but suggested values controlled.",
      "x-eq-source-aliases": ["discipline", "skill", "role", "trade_type", "specialty"],
      "x-eq-suggested-values": ["electrical", "mechanical", "fire", "hydraulic", "civil", "data", "carpentry", "plumbing", "communications"]
    },
    "level": {
      "type": ["string", "null"],
